SELECT id, user_id, username, module, action, request_url, request_method, request_params, response_result, status, error_msg, cost_time, oper_ip, oper_time FROM sys_oper_log
AND module LIKE CONCAT('%', #{query.module}, '%')
AND action LIKE CONCAT('%', #{query.action}, '%')
AND username LIKE CONCAT('%', #{query.username}, '%')
AND status = #{query.status}
AND oper_time >= #{query.startTime}
AND oper_time <= #{query.endTime}
ORDER BY oper_time DESC LIMIT #{query.size} OFFSET #{query.size} * (#{query.page} - 1)

